js, _ := jetstream.New(nc)

stream, _ := js.CreateStream(ctx, jetstream.StreamConfig{
    Name:     "ORDERS",
    Subjects: []string{"orders.>"},
})

consumer, _ := stream.CreateOrUpdateConsumer(ctx, jetstream.ConsumerConfig{
    Durable:       "order-processor",
    AckPolicy:     jetstream.AckExplicitPolicy,
    MaxDeliver:    5,
    BackOff:       []time.Duration{2*time.Second, 10*time.Second, 30*time.Second},
})

for {
    msgs, _ := consumer.Fetch(10)
    for msg := range msgs.Messages() {
        if err := process(msg); err != nil {
            msg.NakWithDelay(5 * time.Second)
            continue
        }
        msg.Ack()
    }
}

// Publisher: stamp each message with a unique ID for deduplication
msg := nats.NewMsg("orders.created")
msg.Header.Set(nats.MsgIdHdr, uuid.New().String())
msg.Data = payload
js.PublishMsg(msg)

// Consumer: AckExplicit + AckSync = exactly-once
js.Subscribe("orders.created", func(msg *nats.Msg) {
    if err := process(msg.Data); err != nil {
        msg.Nak() // triggers redelivery after AckWait
        return
    }
    msg.AckSync() // blocks until server confirms the ack
}, nats.Durable("orders-processor"), nats.AckExplicit())

sub, _ := js.Subscribe("orders.placed", func(msg *nats.Msg) {
	msgID := msg.Header.Get("Nats-Msg-Id")
	if msgID == "" {
		msg.Nak()
		return
	}

	// Atomic guard — SET NX prevents concurrent duplicate processing
	if !store.SetNX(ctx, "processed:"+msgID, 1, 48*time.Hour).Val() {
		msg.Ack() // already handled, drain from pending
		return
	}

	if err := processOrder(msg.Data); err != nil {
		store.Del(ctx, "processed:"+msgID) // rollback guard on failure
		msg.Nak()
		return
	}
	msg.Ack()
},
	nats.Durable("order-processor"),
	nats.AckExplicit(),
	nats.MaxDeliver(5),
)

// NATS 2.9+: declare full retry schedule on the consumer
cfg := jetstream.ConsumerConfig{
    Durable:    "orders-worker",
    MaxDeliver: 4, // len(BackOff) + 1
    AckPolicy:  jetstream.AckExplicitPolicy,
    BackOff:    []time.Duration{5 * time.Second, 30 * time.Second, 2 * time.Minute},
}

// When MaxDeliver is exhausted, capture via advisory and route to DLQ
nc.Subscribe("$JS.EVENT.ADVISORY.CONSUMER.MAX_DELIVERIES.ORDERS.orders-worker",
    func(m *nats.Msg) {
        var adv server.ConsumerMaxDeliveriesAdvisoryV1
        json.Unmarshal(m.Data, &adv)
        raw, _ := js.GetMsg(ctx, "ORDERS", adv.StreamSeq)
        nc.Publish("DEAD.orders", raw.Data)
    },
)

// Cache-aside inside a NATS queue subscriber (Go)
nc, _ := nats.Connect(nats.DefaultURL)

nc.QueueSubscribe("user.fetch.*", "workers", func(msg *nats.Msg) {
    userID := strings.TrimPrefix(msg.Subject, "user.fetch.")
    cacheKey := "user:" + userID

    if cached, err := rdb.Get(ctx, cacheKey).Bytes(); err == nil {
        msg.Respond(cached)
        return
    }

    user := db.FindUser(userID)
    data, _ := json.Marshal(user)
    rdb.Set(ctx, cacheKey, data, 5*time.Minute)
    msg.Respond(data)
})

nc, _ := nats.Connect(nats.DefaultURL)
js, _ := nc.JetStream()

// Durable work-queue stream: one consumer gets each message, deleted on ack
js.AddStream(&nats.StreamConfig{
    Name:      "JOBS",
    Subjects:  []string{"jobs.*"},
    Retention: nats.WorkQueuePolicy,
    Storage:   nats.FileStorage,
    Replicas:  3,
})

// Pull consumer — workers compete; server tracks ack state
sub, _ := js.PullSubscribe("jobs.*", "worker-group")
msgs, _ := sub.Fetch(10, nats.MaxWait(5*time.Second))
for _, msg := range msgs {
    process(msg)
    msg.Ack() // deleted from stream only after explicit ack
}

js, _ := nc.JetStream()

// Log compaction — retain only last message per subject key
js.AddStream(&nats.StreamConfig{
    Name:              "ORDERS",
    Subjects:          []string{"orders.*"},
    MaxMsgsPerSubject: 1,
})

// Consumer group — shared durable queue subscriber
js.QueueSubscribe("orders.*", "processors", handler,
    nats.Durable("order-processor"),
    nats.AckExplicit(),
)

// Offset seek — replay from a specific sequence number
js.Subscribe("orders.*", handler,
    nats.Durable("audit-consumer"),
    nats.StartSequence(1042),
)

js, _ := nc.JetStream()

js.AddStream(&nats.StreamConfig{
    Name:     "ORDERS",
    Subjects: []string{"orders.>"},
})

sub, _ := js.PullSubscribe("orders.us.*", "worker",
    nats.ManualAck(),
    nats.MaxAckPending(10), // prefetch equivalent
)

msgs, _ := sub.Fetch(5, nats.MaxWait(2*time.Second))
for _, msg := range msgs {
    if err := process(msg); err != nil {
        msg.NakWithDelay(5 * time.Second) // requeue with backoff
        continue
    }
    msg.Ack()
}

js, _ := nc.JetStream()

js.AddStream(&nats.StreamConfig{
    Name:     "JOBS",
    Subjects: []string{"jobs.high", "jobs.normal", "jobs.low"},
})

// Rate-limit: max 5 concurrent jobs
js.AddConsumer("JOBS", &nats.ConsumerConfig{
    Durable:       "workers",
    FilterSubject: "jobs.high",
    MaxAckPending: 5,
    AckWait:       30 * time.Second,
})

// Repeatable job every minute
go func() {
    for range time.NewTicker(time.Minute).C {
        js.Publish("jobs.normal", payload)
    }
}()

// Dependency chain: ack then enqueue child
js.Subscribe("jobs.high", func(msg *nats.Msg) {
    process(msg.Data)
    msg.Ack()
    js.Publish("jobs.low", childPayload) // persisted before ack returns
})

js, _ := nc.JetStream()

// Create stream capturing all order events
js.AddStream(&nats.StreamConfig{
    Name:     "ORDERS",
    Subjects: []string{"orders.>"},
    Storage:  nats.FileStorage,
})

// Durable push consumer with explicit ack
js.Subscribe("orders.created", func(msg *nats.Msg) {
    process(msg.Data)
    msg.Ack() // required — no ack = redelivery after AckWait
}, nats.Durable("order-processor"), nats.AckExplicit())

cons, _ := js.CreateOrUpdateConsumer(ctx, "ORDERS", jetstream.ConsumerConfig{
    Durable:       "processor",
    MaxAckPending: 50,
    AckWait:       20 * time.Second,
    MaxDeliver:    5,
})

for {
    msgs, _ := cons.Fetch(10, jetstream.FetchMaxWait(5*time.Second))
    for msg := range msgs.Messages() {
        if err := process(msg); err != nil {
            msg.Nak()
            continue
        }
        msg.Ack()
    }
}

js, _ := jetstream.New(nc)

js.CreateStream(ctx, jetstream.StreamConfig{
    Name:     "EVENTS",
    Subjects: []string{"events.>"},
})

// Publisher: hash entity key into partition subject
subject := fmt.Sprintf("events.p%d", userID%8)
js.Publish(ctx, subject, payload)

// Consumer: pin to one partition for ordered delivery
cons, _ := js.OrderedConsumer(ctx, "EVENTS", jetstream.OrderedConsumerConfig{
    FilterSubjects: []string{"events.p3"},
})
iter, _ := cons.Messages()
for {
    msg, _ := iter.Next()
    process(msg)
    msg.Ack()
}

js, _ := jetstream.New(nc)

shard := crc32.ChecksumIEEE([]byte(orderID)) % 8

cons, _ := js.CreateOrUpdateConsumer(ctx, "ORDERS", jetstream.ConsumerConfig{
    Durable:       fmt.Sprintf("processor-shard-%d", shard),
    FilterSubject: fmt.Sprintf("orders.%d", shard),
    AckPolicy:     jetstream.AckExplicitPolicy,
    MaxAckPending: 100,
})

batch, _ := cons.Fetch(10, jetstream.FetchMaxWait(2*time.Second))
for msg := range batch.Messages() {
    process(msg.Data())
    msg.Ack()
}

js, _ := nc.JetStream()

info, _ := js.ConsumerInfo("ORDERS", "processor")
if info.NumPending > 1000 {
    log.Printf("ALERT: queue depth %d exceeds threshold", info.NumPending)
}
if info.NumAckPending > 100 {
    log.Printf("ALERT: consumer lag — %d unacked messages", info.NumAckPending)
}

// Dead letter: fires when MaxDeliver is exceeded
nc.Subscribe("$JS.EVENT.ADVISORY.CONSUMER.MAX_DELIVERIES.ORDERS.processor",
    func(msg *nats.Msg) {
        log.Printf("ALERT: dead letter advisory — seq poisoned: %s", msg.Data)
        js.Publish("DEAD_LETTER", msg.Data)
    },
)
